const items = $input.all();
const item = items[0];
const documentText = item.json.body?.document_text || item.json.document_text || '';
const source = item.json.body?.source || item.json.source || 'unknown';

if (!documentText || documentText.trim().length === 0) {
  return [{
    json: {
      error: true,
      message: 'document_text is required and cannot be empty',
      received_at: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    document_text: documentText.trim(),
    source: source,
    received_at: new Date().toISOString(),
    document_length: documentText.trim().length
  }
}];

const item = $input.first();
const llmOutput = item.json.text || item.json.output || '';
const inputData = $('Validate Input').first().json;

// Parse LLM JSON output
let classification;
try {
  const jsonMatch = llmOutput.match(/\{[\s\S]*\}/);
  classification = JSON.parse(jsonMatch ? jsonMatch[0] : llmOutput);
} catch (e) {
  classification = {
    category: 'administrative',
    summary: 'Classification failed - defaulting to administrative',
    critical_flags: [],
    language: 'es',
    completeness: 'incomplete'
  };
}

// ============================================
// RULES-BASED URGENCY ENGINE (not LLM-dependent)
// Deterministic rules are auditable and predictable.
// The LLM classifies; rules evaluate urgency.
// ============================================
let urgency = 1;
const text = inputData.document_text.toLowerCase();
const cat = classification.category;

// Critical value patterns (regex)
if (/valor cr[i\u00ed]tico|\*\*\* .* \*\*\*|critical/i.test(text)) {
  urgency = 5;
} else if (cat === 'laboratory' && /\*\* alto \*\*|\*\* bajo \*\*/i.test(text)) {
  urgency = 3;
} else if (cat === 'radiology') {
  urgency = 2;
} else if (cat === 'clinical_note' || cat === 'interconsultation') {
  urgency = 2;
}

// Override: non-empty critical_flags means minimum urgency 4
if (classification.critical_flags && classification.critical_flags.length > 0) {
  urgency = Math.max(urgency, 4);
}

return [{
  json: {
    category: classification.category || 'administrative',
    urgency,
    summary: classification.summary || '',
    critical_flags: classification.critical_flags || [],
    language: classification.language || 'es',
    completeness: classification.completeness || 'complete',
    document_text: inputData.document_text,
    source: inputData.source,
    received_at: inputData.received_at
  }
}];

messageValues.message:
You are a clinical data extraction system for laboratory reports.

Extract structured data and respond ONLY with a JSON object (no markdown, no explanation):

{
  "patient": { "name": "Last, First", "id": "ID or unknown" },
  "date": "YYYY-MM-DD",
  "ordering_physician": "name with title",
  "service": "department or unknown",
  "tests": [
    { "name": "test", "value": number_or_null, "unit": "unit", "reference_low": number_or_null, "reference_high": number_or_null, "flag": "normal|low|high|critical_low|critical_high" }
  ],
  "critical_values": [
    { "test": "name", "value": number, "unit": "unit", "reference_range": "low-high", "deviation": "description" }
  ],
  "data_quality": "complete|partial|poor"
}

Rules:
- Extract ALL test results, not just abnormal ones.
- Flag: within range=normal, slightly outside=low/high, dangerously outside or marked CRITICO=critical_low/critical_high.
- If document is truncated, set data_quality to partial and extract what is available.
- Respond ONLY with JSON.

