const item = $input.first();
return [{
  json: {
    text: JSON.stringify({
      document_type: 'administrative',
      note: 'No AI extraction needed for administrative documents',
      category_detected: item.json.category,
      summary: item.json.summary
    }),
    category: item.json.category,
    urgency: item.json.urgency,
    summary: item.json.summary,
    source: item.json.source,
    received_at: item.json.received_at
  }
}];

const item = $input.first();

// Get classification from upstream
let classification;
try {
  classification = $('Parse Classification & Urgency').first().json;
} catch(e) {
  classification = item.json;
}

// Parse extraction result
let extractedData = {};
const llmOutput = item.json.text || item.json.output || '';

if (llmOutput) {
  try {
    const jsonMatch = llmOutput.match(/\{[\s\S]*\}/);
    extractedData = JSON.parse(jsonMatch ? jsonMatch[0] : llmOutput);
  } catch(e) {
    extractedData = { raw_output: llmOutput, parse_error: true };
  }
}

// Build alerts for critical values
const alerts = [];
if (classification.urgency >= 4) {
  for (const flag of (classification.critical_flags || [])) {
    alerts.push({
      type: 'critical_value',
      message: flag,
      action: 'Notify ordering physician immediately',
      priority: 'URGENT'
    });
  }
  if (alerts.length === 0 && classification.urgency >= 4) {
    alerts.push({
      type: 'high_urgency',
      message: 'Document flagged with high urgency by rules engine',
      action: 'Review promptly',
      priority: 'HIGH'
    });
  }
}

// Determine status
let status = 'success';
if (classification.completeness === 'incomplete') status = 'partial';
if (extractedData.parse_error) status = 'error';

return [{
  json: {
    status,
    classification: {
      category: classification.category,
      urgency: classification.urgency,
      summary: classification.summary,
      language: classification.language || 'es',
      completeness: classification.completeness || 'complete'
    },
    extracted_data: extractedData,
    patient_friendly_summary: null,
    alerts,
    metadata: {
      processed_at: new Date().toISOString(),
      received_at: classification.received_at,
      source: classification.source,
      model: 'qwen3:14b',
      prompt_version: 'v1.0',
      workflow_version: '1.0.0'
    }
  }
}];
